var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배.","JPN":"先輩。","ENG":"Shiyoon...","TWN":"前輩。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"묻고 싶은 게 있어.","JPN":"聞きたいことがあるの。","ENG":"I have something to ask you.","TWN":"我有事情想問你。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐죠? 미나 양.","JPN":"何でしょう、ミナさん。","ENG":"What is it, Mina?","TWN":"是什麼？米娜小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 비숍이 마지막에 한 말...... 무슨 뜻이었을까......?","JPN":"リプレイサー・ビショップの最期の言葉……どういう意味だったのかな……？","ENG":"That last thing the Replacer Bishop said... What do you think she meant by that?","TWN":"克隆大主教最後說的話……是什麼意思啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우린 분명 적이었을 텐데...... 어째서 목숨까지 버려가면서 그런 일을 한 거지?","JPN":"私たちは敵対してたはずなのに……どうして命を捨ててまであんなことを？","ENG":"We were enemies to each other. Why did she have to throw away her life to do something like that?","TWN":"我們明明是敵人……為什麼她不惜放棄自己的生命，也要做出那樣的事？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요......","JPN":"どうでしょうね……","ENG":"Well...","TWN":"這個嘛……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"원래 리플레이서 재생체에게 모체라는 것은 단순히 자신의 설계 기반을 제공한 자를 일컫는 기술적인 단어였을 겁니다.","JPN":"元々リプレイサー再生体にとって「母体」というものは、\\n単に自分の設計基盤を提供した者を指す技術的な単語だったのでしょうね。","ENG":"To regenerated Replacers, \\"source\\" was probably just a technical term referring to the person who provided the base information of their overall design.","TWN":"原本克隆集團再生體的母體，單純是用來稱呼提供設計基盤者的技術用語。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 어떻게 보면 그 강력한 힘과는 별개로 그녀들은 사실 이 세상에 태어난 지 얼마 되지 않은 어린 존재들이라고 할 수도 있죠.","JPN":"でも……ある意味、その強力な力にかかわらず、\\n彼女たちはこの世に生まれたての幼い存在とも言えます。","ENG":"However, apart from their superhuman strength, they were like young children newly born into the world.","TWN":"然而…… 換個角度來看，她們雖然擁有強大的力量，事實上卻可以說是剛誕生在世上不久的年幼存在。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 그녀들이 자신의 모체에게 단순한 설계 제공자의 역할을 넘어 <color=#ffd34c>어머니</color>로서의 애정을 원했다고 해도 이상한 일은 아니겠죠.","JPN":"そんな彼女たちが自分の母体に対し、単に設計提供者の役割以上の、\\n<color=#ffd34c>母</color>としての愛情を求めたとしても、不思議なことではありませんね。","ENG":"Maybe it was natural that what they expected from their sources gradually developed from mere compositional information to <color=#ffd34c>maternal love</color>.","TWN":"這樣的她們沒有把母體當成單純的設計提供者，而是視為<color=#ffd34c>母親</color>來獲得愛，也不是什麼奇怪的事情吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 재생체들은 모체와 관련된 생존자들이 없었으니까 그런 욕구가 강하게 발현되지 않았겠지만......","JPN":"他の再生体には、母体と関わったことのある生存者がおらず、\\nそういった欲求が強く現れていないでしょうけど……","ENG":"As for other regenerated Replacers, such a desire wasn't manifested so strongly because they didn't have any survivors related with their sources.","TWN":"因為其他再生體沒有與母體相關的生存者，所以這種欲望沒有強烈地表現出來……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비숍의 경우는 다르죠.","JPN":"ビショップの場合は別ですね。","ENG":"But it was different in Bishop's case.","TWN":"不過大主教的情況卻不一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"모체와 감정적으로 강력하게 연결된...... 실제로 살아있는 존재가 있었으니까요.","JPN":"母体と強い結びつきがある……実在する人間がいましたから。","ENG":"She had someone that was still alive who had a strong connection to her source.","TWN":"因為有個情感上與母體強烈連接……真實活著的人。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 제 추측일 뿐이지만...... 어쩌면 비숍은 미나 양을 어머니의 친구로 여겼을지도 모릅니다.","JPN":"これは僕の推測でしかありませんが……\\nひょっとすると、ビショップは、ミナさんのことをお母さんの友人として受け止めていたのかもしれません。","ENG":"This is only a guess, but Bishop might have considered you a friend of her mother;","TWN":"雖然這只是我的猜測……但大主教大概把米娜小姐當作自己母親的朋友了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 세상에 유일하게 존재하는 혈육...... 가족으로 말이죠.","JPN":"この世に存在する、たった一人の……家族として。","ENG":"the last person left in this world who she could feel connected to... A family.","TWN":"當成是這世上唯一存在的親人……也就是家人。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배......","JPN":"先輩……","ENG":"Shiyoon...","TWN":"前輩……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나......","JPN":"私……","ENG":"I...","TWN":"我……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가세요, 미나 양.","JPN":"行ってください、ミナさん。","ENG":"Go, Mina.","TWN":"去吧，米娜小姐。"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가서, 세상을 구하고 오세요.","JPN":"行って、世界を救ってください。","ENG":"Go save the world.","TWN":"去拯救世界吧。"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뒤는...... 제가 맡을 테니까요.","JPN":"あとは……僕がなんとかしますから。","ENG":"I'll take care of everything here.","TWN":"之後……就交給我了。"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......고마워.","JPN":"……ありがとう。","ENG":"Thanks.","TWN":"……謝謝。"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부탁할게.","JPN":"任せた。","ENG":"I'll count on you.","TWN":"拜託你了。"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L35_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"어딜! 부사령관님께 가려면 우선 나를 쓰러트려야......!","JPN":"どこを見ている！　副司令官様のところに行きたいなら、私を先に倒すが良い……！","ENG":"Not a chance! You'll have to defeat me first before you go after the Deputy Commander!","TWN":"哪裡走！想去副司令那裡，妳得先打到我……！"},"stage":{"bg":"MAINSTREAM_5508011","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미안하지만 당신의 상대는 접니다.","JPN":"残念ながら、あなたの相手は僕です。","ENG":"I'm sorry, but you'll be dealing with me.","TWN":"不好意思，但妳的對手是我。"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조연은 조연끼리 상대해야 하는 법이니까요.","JPN":"サブキャラ同士で戦うのが筋じゃありませんか。","ENG":"Heroes for heroes, and extras for extras.","TWN":"畢竟配角註定只能與配角演對手戲。"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"주인공의 일에 함부로 끼어드는 건 당신의 역할이 아니에요.","JPN":"主人公にむやみに介入するのは、あなたの役目ではありませんよ。","ENG":"You're overstepping your bounds by trying to interfere with her business.","TWN":"妳扮演的角色可沒有妨礙主角的戲份。"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"이 자식, 무슨 헛소리를......","JPN":"この、ナメたことを……","ENG":"I'm sick of your nonsense!","TWN":"你這傢伙說什麼鬼話……"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"방해하지 마라!!","JPN":"邪魔するな！！","ENG":"Get out of my way!","TWN":"少礙事！！"},"stage":{"bg":"MAINSTREAM_5507010","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴......?","JPN":"ここは……？","ENG":"This place is...","TWN":"這裡是？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_1"},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"긴급탈출용 양자터널로 만들어 낸 차원간 공간이다.","JPN":"緊急脱出用の量子トンネルから生成した次元間の空間だ。","ENG":"This is a crack between dimensions, created by the emergency escape quantum tunnel.","TWN":"是緊急逃脫用的量子隧道造出的次元空間。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_1"},{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"일반적인 차원간 공간은 함선 급의 보호장비가 없이 진입할 경우 몸이 갈갈이 찢어지기 마련이지만,","JPN":"一般的な次元間の空間は、艦船レベルの保護装備を持たずに進入した場合、\\n体がずたずたに裂けてしまうものだが、","ENG":"Normally in a dimensional interspace like this, a human body will be ripped apart without ship-level protection gear.","TWN":"若沒有艦船級的保護裝置就進入一般的次元空間，身體肯定會被撕個粉碎。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_2"},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이건 유지시간이 짧은 대신 그런 부작용을 최소화 해 놓은 곳이지.","JPN":"ここは維持時間が短い代わりに、そんな副作用を最小化した空間だ。","ENG":"This one was designed to minimize such side effects, at the cost of its duration.","TWN":"而這個次元空間維持時間雖然很短，但作為交換，它的副作用也被最小化了。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_3"},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설명 따윈 됐어!","JPN":"説明なんか要らないよ！","ENG":"I don't need your explanation!","TWN":"不需要你的說明！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_2"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 여기서 날 기다린 건가? 도망가지 않고?","JPN":"まさかここで私のことを待ってたの？　あえて逃げずに？","ENG":"Were you waiting for me here? Instead of running away?","TWN":"難道你在這裡等我嗎？沒有逃走？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_3"},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"아무리 퀸, 아니 제이나라고 해도 너희들 모두를 막을 순 없겠지.","JPN":"クイーン、いや、ジェイナがいくら強くても、君ら全員を阻止することはできまい。","ENG":"It wasn't likely that Queen—I mean, Jaina could stop all of you.","TWN":"就算是女皇，不，就算是婕娜也不可能攔住你們所有人吧。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_4"},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그녀의 저지를 뚫고 가장 먼저 이곳에 들어오는 자가 있다면 그건 분명 너일 거라고 생각했다.","JPN":"彼女の制止を振り払って、最も早くここに入る者がいるとしたら、それはきっと君だろうと思ったんだ。","ENG":"And I thought you were definitely going to be the first one to get past her,","TWN":"如果有人能突破她的阻攔最先進到這裡，那個人一定就是妳。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_5"},{"id":"L9_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"유미나.","JPN":"ヤナギ・ミナ。","ENG":"Yoo Mina.","TWN":"劉米娜。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_6"},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 날 기다린 거지?","JPN":"どうして私のことを待ってたの？","ENG":"Why were you waiting for me?","TWN":"你為什麼要等我？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_4"},{"id":"L11_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"비숍의...... 어리석은 선택으로 이번에는 실패했지만 난 포기할 수 없다.","JPN":"ビショップの……愚かな選択によって今回は失敗したが、私は断念できない。","ENG":"Bishop's foolish choice sent everything I've worked for down the drain, but I'm not giving up.","TWN":"因為主教的……愚蠢選擇，我們這次失敗了，但我不能放棄的。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_7"},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서는 제이나를, 리플레이서 계획을 위해 희생한 모두를 볼 낯이 없어.","JPN":"そんなことでは、ジェイナや、リプレイサー計画のために犠牲になった皆に合わせる顔がない。","ENG":"I can't let the sacrifices of Jaina and all the others be in vain.","TWN":"這樣我沒臉去見為了克隆計畫犧牲的所有人。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_8"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 희생시킨 사람들이잖아! 그 사람들 핑계를 대다니 대체 어디까지 맛이 가버린 거야?!","JPN":"あんたのせいで犠牲になったんでしょう！\\nその人たちのことを言い訳にするなんて、いったいどこまで頭がイカれてるわけ！？","ENG":"They're all victims of your ridiculous plan! I can't believe that you're still using them as your excuse!","TWN":"那些人不是你犧牲的嗎！竟然把他們當成藉口，你究竟有多不正常？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_5"},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아직도 현실을 보지 못하는 거야? 네 계획은 이미 끝났어!","JPN":"まだ現実を受け止められないの？　あんたの計画はとっくに終わったんだよ！","ENG":"Isn't it time that you accepted reality? Your plan is over!","TWN":"你還無法面對現實嗎？你的計畫已經結束了！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_6"},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"더 이상 싸워봐야 할 수 있는 건 아무것도 없다고!","JPN":"これ以上戦っても、できることは何もないの！","ENG":"And you will gain nothing from fighting on!","TWN":"你已經沒有什麼好戰鬥了！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_7"},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"아니, 아무것도 끝나지 않았어.","JPN":"いや、何も終わってはいない。","ENG":"No, nothing's over yet.","TWN":"不，一切都沒有結束。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_9"},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"여기서 널 죽이고 네가 가진 대량의 클리포트 인자 원본을 추출한다면 굳이 복제 클리포트 인자 따위에 연연할 필요는 없지.","JPN":"ここで君を殺して、君が持つ大量のクリフォト・ファクターの原本を抽出すれば、\\nクリフォト・レプリカ・ファクターなんかにこだわらなくていいのだ。","ENG":"If I can kill you here and extract the massive amount of original Qliphoth Factors from you, I won't have to mess around with replicated Qliphoth Factors anymore.","TWN":"只要我在這裡殺死妳，提取妳身上的大量逆卡巴拉因子原版，我們就沒必要再執著什麼複製逆卡巴拉因子了。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_10"},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"아직 불멸체 코어도 내 손에 남아 있다. 리플레이서 룩의 동결을 해제하고 테라사이드 시스템을 재기동한다면......","JPN":"不滅体コアもまだ私が持っている。\\nリプレイサー・ルークの凍結を解除して、テラサイドシステムを再起動すれば……","ENG":"I still have the Immortal System Core with me. If I could unfreeze Replacer Rook and restart System Terraside,","TWN":"不滅者核心也還在我手上。只要能解除克隆．城堡的凍結，重新啟動特拉賽德系統……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_11"},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"분명 다시 시작할 수 있겠지.","JPN":"きっと再起できるだろう。","ENG":"we'll be back on track again.","TWN":"我一定可以重新開始。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_THEFOURTH_START","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_12"},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 모습은...... 설마?!","JPN":"その姿は……まさか！？","ENG":"Your appearance... You became a Replacer?","TWN":"你這個模樣……難道？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_8"},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"그래. 그 소년의 말대로 나 또한 불필요한 감상적 태도 따위는 버리기로 했다.","JPN":"あの少年の言うとおり、私も余計に感傷的な姿勢は捨てることにした。","ENG":"You're right. Like that boy said, I've decided to throw all the unnecessary emotions away.","TWN":"沒錯。如那個男孩所說，我也決定放棄不必要的感傷了。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_13"},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"긴급하게 진행한 리플레이서 시술이라 불안정하긴 하지만, 널 상대하기엔 충분하겠지.","JPN":"急いでリプレイサー手術をしたから不安定ではあるが、君を相手にするには十分だろう。","ENG":"It was an urgent procedure that doesn't guarantee much stability, but this will give me enough strength to take you down.","TWN":"雖然緊急進行的克隆集團手術不夠穩定，但要對付妳也足夠了。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_14"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 왜 그렇게까지 하는 거지......? 왜 포기하지 않는 거야?!","JPN":"いったいどうしてそこまでするの……？　なんで諦めないの！？","ENG":"Why do you have to go that far? Why aren't you giving up?","TWN":"你到底為什麼要做到這個地步？為什麼不放棄啊？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_9"},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇게나 세상을 파괴하고 싶어?!","JPN":"そこまでして世界を壊したいわけ！？","ENG":"Why do you want to destroy this world so badly?","TWN":"你就這麼想毀滅世界嗎？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_10"},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"천만에. 난 인류를 구하려는 것뿐이다.","JPN":"とんでもない、私は人類を救いたいだけだ。","ENG":"You're not listening. What I'm doing is trying to save mankind.","TWN":"怎麼會，我只是想要拯救人類而已。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_15"},{"id":"L26_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"말했을 텐데? 종말이 다가오고 있다고.","JPN":"さっき言っただろう？　終末が近づいていると。","ENG":"I told you, doomsday is coming.","TWN":"我不是說了嗎？末日正在接近。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_16"},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 어쨌다는 거야? 네 말이 사실이라고 해도 그럼 차라리 그때 가서 종말을 막으면 되잖아?!","JPN":"だから、何？　あんたの話が本当だとしても、訪れた時に阻止すればいいんでしょ！？","ENG":"So what? Even if that's true, why can't you just wait until it comes and stop it then?","TWN":"那又怎樣？就算你說的是真的，那到時再阻止末日不就好了嗎？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_11"},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"어떻게?","JPN":"どうやって？","ENG":"How?","TWN":"怎麼阻止？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_17"},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어떻게라니? 어떻게는 무슨 어떻게야?!","JPN":"どうやってって？　それを考えればいいでしょ！？","ENG":"Huh? How? What do you mean, how?","TWN":"什麼怎麼阻止？到底什麼怎麼阻止啊？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_12"},{"id":"L32_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"나라고 그 생각을 해 보지 않았을 것 같나?","JPN":"そんなこと、私が考えなかったと思うか？","ENG":"Do you think I didn't consider every option?","TWN":"妳以為我沒有那樣想過嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_18"},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"다른 멸망한 세계의 사람들은 싸워보지 않았을까?","JPN":"他の滅亡した世界の人々は抗わなかったと思うか？","ENG":"Do you think humanity in the previous worlds didn't put up a fight?","TWN":"其他滅亡世界的人們也試著戰鬥過了吧？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_19"},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"네 말대로 저항해볼 수도 있겠지.","JPN":"君のいうとおり、抵抗できないこともないだろう。","ENG":"We can choose to resist, like you said.","TWN":"我們也可以照妳所說，試著抵抗末日。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_20"},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"하지만 그게 얼마나 갈까? 5년? 10년?","JPN":"だが、それはどれくらい持つかな？　5年？　それとも、10年？","ENG":"But how long do you think we'd last? Five years? Ten?","TWN":"但那又能撐多久？5年？10年？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_21"},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"운이 좋다면 100년 정도는 버틸 수도 있겠군.","JPN":"運がよければ、100年ぐらいは持つかもしれない。","ENG":"We'd last a hundred years if we're lucky.","TWN":"運氣好的話說不定能撐上100年。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_22"},{"id":"L38_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"하지만 결국 한계가 온다.","JPN":"だが、結局限界があるんだ。","ENG":"But it's only a matter of time.","TWN":"但那終究是有極限的。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_23"},{"id":"L39_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"과거에 싸움을 택했던 다른 세계들도...... 결국 어느 하나 멸망의 운명을 피하지 못했어!","JPN":"かつて戦うことを選んだ他の世界も……\\n結局誰も滅亡の運命から逃れられなかったんだ！","ENG":"Not a single world that chose to fight was able to overcome their fated doom!","TWN":"過去選擇抗爭的其他世界……最終也都沒有一個逃過滅亡的命運！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_24"},{"id":"L40_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"그런데 어떻게 그렇게 간단하게 싸우자는 말을 할 수가 있지?!","JPN":"なのに、どうしてそんなに簡単に戦おうだなんて言えるんだ！？","ENG":"How can you speak of fighting so irresponsibly?","TWN":"那妳又怎麼能這麼輕易就說出去戰鬥這種話？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_25"},{"id":"L41_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"네가 그 대가를 책임질 수 있나?!","JPN":"君は、その代価の責任をとれるのか！？","ENG":"Can you take all the consequences?","TWN":"妳能承擔那個代價嗎？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_26"},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 당신은! 당신이 인류를 희생시키며 저지른 짓을 책임질 수 있어?!","JPN":"じゃあ、あんたは？　あんたは人類を犠牲にしたことに対して、責任がとれるの！？","ENG":"What about you? How are you going to take the consequences for all the sacrifices to be made?","TWN":"那你呢！你能承擔犧牲人類的責任嗎？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_13"},{"id":"L43_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 프로젝트란 건 그렇게 완벽한 거야?","JPN":"テラサイドプロジェクトって、そんなに完璧なものなの？","ENG":"Is this thing called Project Terraside really that perfect?","TWN":"特拉賽德計畫有這麼完美嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_14"},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신의 계획을 따르면 정말로 인류가 살아날 수 있어? 무슨 수로 장담하는 거지?","JPN":"あんたの計画に従えば、本当に人類は助かるの？　どうして断言できるの？","ENG":"Are you sure mankind will be able to carry on if they all follow your plan? How can you be so sure?","TWN":"按照你的計畫，人類真的能存續下去嗎？你能做出什麼保證？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_15"},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"5종 침식체로 변해버린 극소수의 인간들을...... 정말로 더 이상 인간이라고 할 수 있냐고?","JPN":"第5種侵食体になってしまった、ごく一部の人間を……本当に人間だって言えるの？","ENG":"What will be left is a very small group of Category 5 C.O.s that used to be humans. Can you really call them mankind?","TWN":"那些變為5級侵蝕體的極少數人類……他們真的還能被稱作是人類？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_16"},{"id":"L47_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這個……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_27"},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배의 말처럼, 사람에겐 누구나 양보해선 안 되는 것들이 있어.","JPN":"先輩も言ってたとおり、人間は誰しも譲れないところがある。","ENG":"Shiyoon's right. Everyone has something that they can't compromise on.","TWN":"就像前輩說的，每個人都有無法讓步的事情。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_17"},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설사 끝까지 지켜내지 못할 것 같아 겁이 나더라도...... 고개를 돌리면 안 된다는 걸......","JPN":"たとえ最後まで守れそうになくて怖くなっても……背を向けてはならないということを……","ENG":"I may run into obstacles that seem great enough to make me lose myself eventually, but I must stay firm and face them.","TWN":"就算你害怕無法守護到最後……也不能回頭……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_18"},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"비숍은 목숨을 걸고 나에게 가르쳐 줬어.","JPN":"ビショップは命がけで私に教えてくれた。","ENG":"Bishop's death taught me that.","TWN":"大主教用自己的性命教會了我這兩件事。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_19"},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 당신은 둘 중 어느 것도 깨닫지 못했지.","JPN":"でも、あんたはなにもわかってない。","ENG":"But you didn't realize either of them.","TWN":"但你完全不明白這兩件事。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_20"},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 당신이 어떤 미래를 보고 마음이 병들었는지는 모르겠지만......","JPN":"あんたがいったいどんな未来を見て、心を病んでしまったかはわからないけど……","ENG":"I don't know what future you saw that was so devastating it crippled your mind,","TWN":"雖然不知道你到底看見了什麼樣的未來，才會有這種病態的心理，但是……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_21"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"양보해선 안될 걸 양보했을 때, 당신은 이미 부서졌던 거야.","JPN":"譲ってはならないものを譲った時に、あんたはすでに壊れてしまったんだよ。","ENG":"but in fact, you became broken the moment you made a compromise on what you shouldn't have.","TWN":"但在不能讓步的事情上做出讓步的那一刻，你就已經壞掉了。"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_22"},{"id":"L4_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신은 그저 스스로가 만들어 낸 망상에 취해 당신과 당신이 따르는 사람들의 존엄까지 팔아 치워버린 겁쟁이일 뿐이야!","JPN":"あんたは自らの妄想に浸って、あんたやあんたに従う人々の\\n尊厳まで奪ってしまった臆病者に過ぎない！","ENG":"You're just a coward who got blinded by your own fear and threw the dignity of your followers in the trash!","TWN":"你只是沉醉於自己製造的妄想，出賣了你，和追隨你的人們的尊嚴，你不過是個懦夫罷了！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_23"},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"시끄러워!","JPN":"うるさい！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_28"},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"내게 필요한 건 네 설교 따위가 아니라 실질적인 구원이다!","JPN":"私に必要なのは君の説教なんかではない！　救済だ！","ENG":"What I need is an actual salvation, not a lecture!","TWN":"我需要的不是妳的說教，而是妳實際的救助！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_29"},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"그걸 제시할 수 없다면 네 말 역시 모두 무가치할 뿐이지!","JPN":"それを示すことができないなら、君に何と言われようが、何の価値もない！","ENG":"If you can't provide it, no word you say has any value at all!","TWN":"如果妳無法提供我需要的東西，那妳說的話也全都毫無價值！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_30"},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이건?!","JPN":"これは！？","ENG":"What's this?","TWN":"這是？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_24"},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"이 불안정한 양자터널은 강력한 정신오염 지대다! 역으로 말하자면 각자의 정신적 영향력이 극대화되는 곳이라고도 할 수 있지!","JPN":"この不安定な量子トンネルは、強力な精神汚染エリアだ！\\n逆に言うと、それぞれの精神的な影響力が極限に達する場所とも言える！","ENG":"This unstable quantum tunnel is a potent mental contamination zone! In other words, the spiritual strength and its influence on reality get maximized while we're here.","TWN":"這個不穩定的量子隧道是強烈的精神污染地帶！\\n反過來說，這裡也是我們各自的精神影響力最大的地方！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_31"},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"난 이곳에서 나와 정신적 유대관계로 묶인 자들의 <color=#ffd34c>실체화된 환영</color>을 불러올 수 있다!","JPN":"私はここで、自分と精神的な絆で結ばれている者たちの、\\n<color=#ffd34c>実体化した幻影</color>を呼び寄せることができる！","ENG":"Here, I can call upon the <color=#ffd34c>materialized illusions</color> of the ones I have a strong mental bond with!","TWN":"我可以在這裡以<color=#ffd34c>實體化幻影</color>的形式，\\n召喚出那些與我有精神羈絆聯繫的人！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_32"},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"이들 모두를 상대로 네게 승산 따위는 없어!","JPN":"彼ら全員を相手に、君に勝ち目などない！","ENG":"You stand no chance against so many of them.","TWN":"與他們所有人為敵，妳完全沒有勝算！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_33"},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"그러니 순순히 포기하고 테라사이드 시스템의 부활을 위해 네 피를 바쳐라!","JPN":"だから、おとなしく諦めて、テラサイドシステムの復活のために君の血を捧げたまえ！","ENG":"So give up and offer me your blood for System Terraside's resurrection!","TWN":"所以妳就乖乖放棄，為了特拉賽德系統的復活獻出鮮血吧！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_34"},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇군...... 그러니까 일종의 심상공간 같은 거다 이거지?","JPN":"なるほど……つまり、ある種の心象空間みたいなものってことだよね？","ENG":"I see... So it's like a place of imagination, right?","TWN":"是嗎……也就是說，這裡是某種想像空間的地方吧？"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_25"},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"어, 어떻게?!","JPN":"ど、どうやって！？","ENG":"H-how did you...","TWN":"怎、怎麼會？！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_35"},{"id":"L26_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"실체화된 환영을 불러내는 건 강력한 정신력 컨트롤이 필요한 일이다!","JPN":"実体化した幻影を呼び起こすには、強力なマインドコントロールが必要なんだ！","ENG":"Summoning materialized illusions requires a highly advanced spiritual control!","TWN":"要召喚實體化幻影，需要強大的精神控制能力！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_36"},{"id":"L27_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"절대로 이 곳에 처음 들어온 자가 해낼만한 일이 아니야!","JPN":"決してここを初めて経験する者にできるようなことではない！","ENG":"It's just not possible for someone who has never been here before!","TWN":"第一次來這裡的人是絕對不可能做到的！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_TRANS","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_REPLACER_CA_KING_IN_TRAILER_37"},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그야 처음이 아니니까 그렇지!","JPN":"そりゃ、初めてじゃないからだよ！","ENG":"This isn't my first time.","TWN":"因為我不是第一次來到這裡！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_26"},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이런 공간에서 환영을 만들어 내는 건 예전에도 한 번 겪어봤거든!","JPN":"こんな空間で幻影を生成するのは、以前にも一度経験したことがあるからね！","ENG":"I've been in a place where I had to create illusions with my mind.","TWN":"在這種空間製造出幻影，我以前也曾經體驗過！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_27"},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 덤벼!","JPN":"だから、かかってこい！","ENG":"So come at me!","TWN":"所以來吧！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_28"},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 헛된 망상에 끝을 내주지!","JPN":"あんたのバカげた妄想に、終止符を打ってあげるよ！","ENG":"I will wake you up from your daydream!","TWN":"讓我來結束你徒然的妄想！"},"stage":{"bg":"MIND","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_CA_YOO_MI_NA_IN_TRAILER_29"}]`);export{e as default};